/* ── Structured orchestrator event handler ───────────────── */

export type OrchEvent =
  | { type: 'phase_changed'; phase: string; detail?: string; task_count?: number; wave_count?: number; plan_id?: string; master_agent?: string }
  | { type: 'task_assigned'; agent: string; description: string; prompt?: string; dag_id?: string }
  | { type: 'task_completed'; dag_id?: string; summary?: string; exit_code?: number }
  | { type: 'task_failed'; dag_id?: string; summary?: string; exit_code?: number }
  | { type: 'decomposition_failed'; error: string }
  | { type: 'wave_progress'; current: number; total: number }
  | { type: 'task_skipped'; dag_id: string; reason: string }
  | { type: 'task_retrying'; dag_id: string; attempt: number; max_retries: number }
  | { type: 'task_fallback'; dag_id: string; from_agent: string; to_agent: string }
  | { type: 'rate_limited'; dag_id: string; wait_seconds: number }
  | { type: 'master_timeout'; timeout_minutes: number }
  | { type: 'worker_timeout'; timeout_minutes: number }
  | { type: 'review_timeout'; timeout_minutes: number }
  | { type: 'question'; agent: string; content: string; plan_id?: string }
  | { type: 'question_answered'; agent: string }
  | { type: 'dispatch_error'; dag_id: string; error: string }
  | { type: 'worker_output'; dag_id: string; line: string }
  | { type: 'worker_started'; dag_id: string; process_id: string }
  | { type: 'diffs_ready'; diffs: Array<{ dag_id: string; branch_name: string; file_count: number; additions: number; deletions: number }> }
  | { type: 'info'; message: string };

const lastOutputUpdateByDag = new Map<string, number>();

export function handleOrchEvent(
  ev: OrchEvent,
  masterAgent: ToolName,
  subTaskQueue: string[],
  dagToFrontendId: Map<string, string>,
  dagCounter: number,
) {
  const store = useTaskStore.getState();
  type LogLevel = 'info' | 'success' | 'warn' | 'cmd' | 'error';
  const log = (level: LogLevel, message: string) =>
    store.addOrchestrationLog({ agent: masterAgent, level, message });

  switch (ev.type) {
    case 'phase_changed': {
      const phase = ev.phase;
      if (phase === 'decomposing') {
        lastOutputUpdateByDag.clear();
        store.setOrchestrationPhase('decomposing');
        // Set activePlan early from enriched event so it's available before awaiting_approval
        if (ev.plan_id) {
          store.setActivePlan({
            task_id: ev.plan_id,
            master_agent: ev.master_agent ? asToolName(ev.master_agent) : masterAgent,
            master_process_id: null,
          });
        }
        log('cmd', `Phase 1: ${ev.detail || 'Decomposing'}`);
      } else if (phase === 'awaiting_approval') {
        store.setOrchestrationPhase('awaiting_approval');
        log('info', `${ev.task_count} sub-tasks ready for approval`);
      } else if (phase === 'executing') {
        store.setOrchestrationPhase('executing');
        // Move pending worker tasks to running
        for (const [id, task] of store.tasks) {
          if (task.status === 'pending' && task.role === 'worker') {
            store.updateTaskStatus(id, 'running');
          }
        }
        log('cmd', `Phase 2: Executing ${ev.task_count ?? ''} sub-tasks in ${ev.wave_count ?? ''} wave(s)`);
      } else if (phase === 'reviewing') {
        store.setOrchestrationPhase('reviewing');
        log('cmd', `Phase 3: ${ev.detail || 'Reviewing'}`);
      }
      break;
    }

    case 'task_assigned': {
      const agent = ev.agent;
      const desc = ev.description;
      const prompt = ev.prompt || desc; // Full prompt from backend, fallback to description
      const subId = crypto.randomUUID();
      const phase2Already = store.orchestrationPhase === 'executing';
      store.addTask({
        taskId: subId,
        prompt,
        toolName: asToolName(agent),
        status: phase2Already ? 'running' : 'pending',
        description: desc.length > 60 ? desc.slice(0, 57) + '...' : desc,
        startedAt: phase2Already ? Date.now() : null,
        dependsOn: null,
        role: 'worker',
      });
      subTaskQueue.push(subId);
      dagToFrontendId.set(ev.dag_id ?? `t${dagCounter + 1}`, subId);
      log('info', `Assigned to ${agent}: ${desc}`);
      break;
    }

    case 'task_completed':
    case 'task_failed': {
      if (!ev.dag_id) {
        console.warn(`${ev.type} received without dag_id — cannot match to frontend task`);
      }
      const status: TaskStatus = ev.type === 'task_completed' ? 'completed' : 'failed';
      const targetId = ev.dag_id ? dagToFrontendId.get(ev.dag_id) : undefined;
      if (!targetId && ev.dag_id) {
        console.warn(`Unmatched dag_id in ${ev.type}: ${ev.dag_id}`);
      }
      if (targetId) {
        store.updateTaskStatus(targetId, status);
        // Clean up queue entry if present
        const queueIdx = subTaskQueue.findIndex(id => dagToFrontendId.get(ev.dag_id!) === id);
        if (queueIdx !== -1) subTaskQueue.splice(queueIdx, 1);
      }
      const summary = ev.summary || '';
      log(
        ev.type === 'task_completed' ? 'success' : 'error',
        `${ev.type === 'task_completed' ? 'Completed' : 'Failed'} (exit ${ev.exit_code}): ${summary.slice(0, 200)}`,
      );
      // Emit notification for task completion/failure
      emitOrchestrationNotification(
        ev.type === 'task_completed' ? 'success' : 'error',
        ev.type === 'task_completed' ? 'Task Completed' : 'Task Failed',
        summary.slice(0, 100) || undefined,
        targetId ? { label: 'View', taskId: targetId } : undefined,
      );
      break;
    }

    case 'wave_progress': {
      log('info', `\u27D0 Wave ${ev.current}/${ev.total}`);
      break;
    }

    case 'task_skipped': {
      const dagId = ev.dag_id;
      const frontendId = dagToFrontendId.get(dagId);
      if (frontendId) {
        store.updateTaskStatus(frontendId, 'blocked');
        const qIdx = subTaskQueue.indexOf(frontendId);
        if (qIdx !== -1) subTaskQueue.splice(qIdx, 1);
      }
      log('warn', `Skipping ${dagId}: ${ev.reason}`);
      break;
    }

    case 'task_retrying': {
      const dagId = ev.dag_id;
      const frontendId = dagToFrontendId.get(dagId);
      if (frontendId) {
        store.updateTaskStatus(frontendId, 'retrying');
        const qIdx = subTaskQueue.indexOf(frontendId);
        if (qIdx !== -1) subTaskQueue.splice(qIdx, 1);
        subTaskQueue.push(frontendId);
      }
      log('info', `Retrying ${dagId} (attempt ${ev.attempt}/${ev.max_retries})`);
      break;
    }

    case 'task_fallback': {
      const dagId = ev.dag_id;
      const newAgent = ev.to_agent;
      const frontendId = dagToFrontendId.get(dagId);
      if (frontendId) {
        const task = store.tasks.get(frontendId);
        if (task) {
          const newTasks = new Map(store.tasks);
          newTasks.set(frontendId, { ...task, toolName: asToolName(newAgent), status: 'falling_back' });
          useTaskStore.setState({ tasks: newTasks });
        }
      }
      log('info', `Falling back: ${dagId} reassigned from ${ev.from_agent} to ${newAgent}`);
      break;
    }

    case 'rate_limited': {
      log('warn', `Rate limited on ${ev.dag_id} — waiting ${ev.wait_seconds}s`);
      break;
    }

    case 'master_timeout':
    case 'worker_timeout':
    case 'review_timeout': {
      log('error', `${ev.type.replace('_', ' ')} after ${ev.timeout_minutes} minutes`);
      break;
    }

    case 'question': {
      log('info', `${ev.agent} asks: ${ev.content}`);
      // Set pending question so the UI shows the answer prompt
      if (ev.plan_id) {
        store.setPendingQuestion({
          questionId: `q-${Date.now()}`,
          sourceAgent: ev.agent,
          content: ev.content,
          planId: ev.plan_id,
        });
      }
      // Notify user — especially useful when app is in background
      emitOrchestrationNotification(
        'warning',
        `${ev.agent} has a question`,
        String(ev.content).slice(0, 100),
        { label: 'Answer' },
      );
      break;
    }

    case 'question_answered': {
      log('info', `Master answered ${ev.agent}'s question`);
      store.setPendingQuestion(null);
      break;
    }

    case 'dispatch_error': {
      log('error', `Dispatch failed for ${ev.dag_id}: ${ev.error}`);
      break;
    }

    case 'info': {
      log('info', ev.message);
      break;
    }

    case 'worker_output': {
      const frontendId = dagToFrontendId.get(ev.dag_id);
      if (frontendId) {
        const now = Date.now();
        const lastUpdate = lastOutputUpdateByDag.get(ev.dag_id) ?? 0;
        if (now - lastUpdate > 500) {
          lastOutputUpdateByDag.set(ev.dag_id, now);
          store.updateTaskOutputLine(frontendId, ev.line);
        }
      }
      break;
    }

    case 'worker_started': {
      // Future use: track worker process IDs
      break;
    }

    case 'diffs_ready': {
      const entries = new Map<string, WorktreeReviewEntry>();
      for (const d of ev.diffs) {
        entries.set(d.dag_id, {
          dagId: d.dag_id,
          branchName: d.branch_name,
          fileCount: d.file_count,
          additions: d.additions,
          deletions: d.deletions,
        });
      }
      store.setWorktreeEntries(entries);
      log('info', `Diffs ready: ${ev.diffs.length} worktrees`);
      break;
    }

    case 'decomposition_failed': {
      log('error', ev.error);
      // Use fresh state to find the master task
      const currentTasks = useTaskStore.getState().tasks;
      for (const [id, t] of currentTasks) {
        if (t.role === 'master') {
          store.updateTaskResult(id, ev.error);
          break;
        }
      }
      break;
    }
  }
}

import { useCallback } from 'react';
import { Channel } from '@tauri-apps/api/core';
import { commands } from '../../bindings';
import type { OutputEvent } from '../../bindings';
import {
  emitProcessOutput,
  emitLocalProcessMessage,
  useProcessStore,
} from '../useProcess';
import { useTaskStore, type ToolName, type TaskStatus, type OrchestratorConfig } from '../../stores/taskStore';
import { handleOrchEvent } from './handleOrchEvent';

/**
 * Hook that provides the `dispatchOrchestratedTask` function for multi-agent orchestration.
 */
export function useOrchestratedDispatch() {
  const dispatchOrchestratedTask = useCallback(
    async (
      prompt: string,
      projectDir: string,
      orchestratorConfig: OrchestratorConfig,
    ): Promise<Map<ToolName, string>> => {
      const results = new Map<ToolName, string>();

      // Create channel for orchestration output (all phases stream through this)
      const channel = new Channel<OutputEvent>();
      const orchestrationId = crypto.randomUUID();

      // Buffer for capturing agent result text to attach to completing tasks
      let lastResultText = '';
      // Ordered queue of sub-task IDs for matching sequential completion messages
      const subTaskQueue: string[] = [];
      // Map DAG IDs (t1, t2, ...) to frontend task IDs — assigned in order
      const dagToFrontendId = new Map<string, string>();
      let dagCounter = 0;

      channel.onmessage = (msg: OutputEvent) => {
        if (msg.event === 'exit') {
          const code = Number(msg.data);
          useProcessStore.getState()._updateStatus(
            orchestrationId,
            code === 0 ? 'completed' : 'failed',
            code,
          );
          emitProcessOutput(orchestrationId, msg);
          return;
        }
        emitProcessOutput(orchestrationId, msg);

        if (msg.event === 'stdout' && msg.data) {
          const line = msg.data;
          const masterAgent = orchestratorConfig.masterAgent;

          // --- Structured orchestrator events (@@orch:: prefix) ---
          if (line.startsWith('@@orch::')) {
            try {
              const ev = JSON.parse(line.slice(8));
              handleOrchEvent(ev, masterAgent, subTaskQueue, dagToFrontendId, dagCounter);
              if (ev.type === 'task_assigned') dagCounter++;
            } catch (e) { console.error('Malformed orch event:', e); }
            return;
          }

          // --- NDJSON agent output (Claude/Gemini result events) ---
          if (line.startsWith('{')) {
            try {
              const ev = JSON.parse(line);
              if (ev.type === 'result') {
                const resultText = ev.result || ev.response;
                let isDecompositionJson = false;
                if (resultText) {
                  try {
                    const parsed = typeof resultText === 'string' ? JSON.parse(resultText) : null;
                    if (parsed && Array.isArray(parsed.tasks) && parsed.tasks[0]?.agent) {
                      isDecompositionJson = true;
                    } else if (parsed && Array.isArray(parsed.sub_tasks) && parsed.sub_tasks[0]?.assigned_agent) {
                      isDecompositionJson = true;
                    }
                  } catch (e) { /* not decomposition JSON */ }
                }
                if (resultText && !isDecompositionJson) {
                  lastResultText = resultText.length > 800 ? resultText.slice(0, 797) + '...' : resultText;
                  if (resultText.length < 500) {
                    useTaskStore.getState().addOrchestrationLog({
                      agent: masterAgent,
                      level: 'success',
                      message: resultText.length > 200 ? resultText.slice(0, 200) + '...' : resultText,
                    });
                  }
                }
                const inputTokens = ev.usage?.input_tokens ?? ev.stats?.input_tokens ?? null;
                const outputTokens = ev.usage?.output_tokens ?? ev.stats?.output_tokens ?? null;
                const totalTokens = ev.usage?.total_tokens ?? ev.stats?.total_tokens
                  ?? (inputTokens != null && outputTokens != null ? inputTokens + outputTokens : null);
                useTaskStore.getState().updateAgentContext(masterAgent, {
                  toolName: masterAgent,
                  inputTokens,
                  outputTokens,
                  totalTokens,
                  costUsd: typeof ev.total_cost_usd === 'number' ? ev.total_cost_usd : null,
                  status: ev.is_error ? 'failed' : 'completed',
                });
              }
            } catch (e) { /* not valid JSON */ }
          }
          // Skip all other raw text (MCP warnings, echoed prompts, verbose agent output)
        }
      };

      // Register orchestration as a single process in frontend
      const store = useProcessStore.getState();
      const newProcesses = new Map(store.processes);
      const description = prompt.length > 60 ? prompt.slice(0, 57) + '...' : prompt;
      newProcesses.set(orchestrationId, {
        taskId: orchestrationId,
        cmd: `orchestration: ${description}`,
        status: 'running',
        channel,
        startedAt: Date.now(),
        hasOutput: false,
        lastEventAt: Date.now(),
        lastOutputPreview: 'Master orchestration started. Worker output will stream here.',
      });
      useProcessStore.setState({
        processes: newProcesses,
        activeProcessId: orchestrationId,
      });

      emitLocalProcessMessage(orchestrationId, `$ ${prompt}`);

      try {
        // Convert frontend config format (camelCase) to backend format (snake_case)
        const backendConfig = {
          agents: orchestratorConfig.agents.map(a => ({
            tool_name: a.toolName,
            sub_agent_count: a.subAgentCount,
            is_master: a.isMaster,
          })),
          master_agent: orchestratorConfig.masterAgent,
        };

        const result = await commands.dispatchOrchestratedTask(
          prompt,
          projectDir,
          backendConfig,
          channel,
        );

        if (result.status === 'ok') {
          const plan = result.data;
          const taskState = useTaskStore.getState();

          // Determine final phase status
          const phaseStr = plan.phase as string;
          const isFailure = phaseStr === 'Failed';
          const finalStatus: TaskStatus = isFailure ? 'failed' : 'completed';

          // Update the initial orchestration task that was added immediately at launch
          // Find it: it's the task with status 'running' matching the prompt
          const currentTasks = taskState.tasks;
          for (const [id, t] of currentTasks) {
            if (t.status === 'running' && t.prompt === prompt) {
              taskState.updateTaskStatus(id, finalStatus);
              // Attach final result summary to the master task
              if (lastResultText) {
                taskState.updateTaskResult(id, lastResultText);
                lastResultText = '';
              }
              break;
            }
          }

          // Add any sub-tasks that weren't already tracked via real-time events
          for (const subTask of plan.sub_tasks) {
            results.set(subTask.assigned_agent as ToolName, subTask.id);
            const alreadyTracked = Array.from(taskState.tasks.values()).some(
              t => t.prompt === subTask.prompt
            );
            if (!alreadyTracked) {
              taskState.addTask({
                taskId: subTask.id,
                prompt: subTask.prompt,
                toolName: subTask.assigned_agent as ToolName,
                status: 'completed',
                description: subTask.prompt.length > 60 ? subTask.prompt.slice(0, 57) + '...' : subTask.prompt,
                startedAt: Date.now(),
                dependsOn: null,
              });
            }
          }

          // Store active plan for /clear command
          taskState.setActivePlan({
            task_id: plan.task_id,
            master_agent: plan.master_agent,
            master_process_id: plan.master_process_id,
          });

          // Mark orchestration phase as completed or failed
          taskState.setOrchestrationPhase(isFailure ? 'failed' : 'completed');

          useProcessStore.getState()._updateStatus(orchestrationId, finalStatus, isFailure ? -1 : 0);
        } else {
          console.error('Orchestration failed:', result.error);
          useProcessStore.getState()._updateStatus(orchestrationId, 'failed', -1);
          useTaskStore.getState().setOrchestrationPhase('failed');
          throw new Error(result.error);
        }
      } catch (e) {
        console.error('Orchestration error:', e);
        useProcessStore.getState()._updateStatus(orchestrationId, 'failed', -1);
        const taskState = useTaskStore.getState();
        taskState.setOrchestrationPhase('failed');

        // Mark any running tasks as failed
        for (const [id, t] of taskState.tasks) {
          if (t.status === 'running') {
            taskState.updateTaskStatus(id, 'failed');
          }
        }

        throw e;
      }

      return results;
    },
    [],
  );

  return { dispatchOrchestratedTask };
}

// Helper: parse decomposition JSON from agent output
// ---------------------------------------------------------------------------

/// Extract `DecompositionResult` from the agent's collected output lines.
/// Tries the adapter's `extract_result()` first, then falls back to scanning
/// output for JSON.
fn parse_decomposition_from_output(
    output_lines: &[String],
    adapter: &dyn ToolAdapter,
) -> Option<DecompositionResult> {
    debug!("[orchestrator] parse_decomposition: {} output lines to parse", output_lines.len());

    // Strategy A: Try adapter's extract_result first (looks for "result" event)
    if let Some(result_text) = adapter.extract_result(output_lines) {
        debug!("[orchestrator] adapter.extract_result returned {} chars", result_text.len());
        if let Some(decomp) = parse_decomposition_json(&result_text) {
            return Some(normalize_decomposition_agents(decomp));
        }
    }

    // Strategy B: Extract text content from NDJSON message/result events
    // Claude returns decomposition JSON inside message content blocks or result text
    let mut extracted_texts: Vec<String> = Vec::new();
    let mut extracted_bytes: usize = 0;
    const MAX_EXTRACTED_BYTES: usize = 1_048_576; // 1MB safety limit
    for line in output_lines {
        if extracted_bytes > MAX_EXTRACTED_BYTES {
            log::warn!("[orchestrator] Strategy B: extracted text exceeded 1MB limit, stopping accumulation");
            break;
        }
        let trimmed = line.trim();
        if !trimmed.starts_with('{') { continue; }
        if let Ok(parsed) = serde_json::from_str::<serde_json::Value>(trimmed) {
            let event_type = parsed.get("type").and_then(|t| t.as_str()).unwrap_or("");
            match event_type {
                "message" | "assistant" => {
                    // Extract text from content blocks
                    if let Some(content) = parsed.get("content") {
                        if let Some(arr) = content.as_array() {
                            for block in arr {
                                if let Some(text) = block.get("text").and_then(|t| t.as_str()) {
                                    extracted_bytes += text.len();
                                    extracted_texts.push(text.to_string());
                                }
                            }
                        } else if let Some(text) = content.as_str() {
                            extracted_bytes += text.len();
                            extracted_texts.push(text.to_string());
                        }
                    }
                }
                "result" => {
                    if let Some(result) = parsed.get("result").and_then(|r| r.as_str()) {
                        extracted_bytes += result.len();
                        extracted_texts.push(result.to_string());
                    }
                    if let Some(response) = parsed.get("response").and_then(|r| r.as_str()) {
                        extracted_bytes += response.len();
                        extracted_texts.push(response.to_string());
                    }
                }
                _ => {}
            }
        }
    }

    // Try parsing extracted texts (most likely to contain the JSON)
    if !extracted_texts.is_empty() {
        let combined_text = extracted_texts.join("\n");
        debug!("[orchestrator] extracted {} text segments, {} total chars", extracted_texts.len(), combined_text.len());
        if let Some(decomp) = parse_decomposition_json(&combined_text) {
            debug!("[orchestrator] parse from extracted text succeeded");
            return Some(normalize_decomposition_agents(decomp));
        }
        // Also try each segment individually
        for text in &extracted_texts {
            if let Some(decomp) = parse_decomposition_json(text) {
                debug!("[orchestrator] parse from individual segment succeeded");
                return Some(normalize_decomposition_agents(decomp));
            }
        }
    }

    // Strategy C: Fall back to scanning raw output lines
    let combined = output_lines.join("\n");
    debug!("[orchestrator] falling back to raw combined output: {} chars", combined.len());
    let result = parse_decomposition_json(&combined);

    // Normalize agent names in the decomposition result
    result.map(normalize_decomposition_agents)
}

/// Normalize agent names in a decomposition result.
/// Maps common LLM hallucinations and variations to valid agent names:
/// - "claude code", "claude-code", "Claude" → "claude"
/// - "gemini cli", "gemini-cli", "Gemini" → "gemini"
/// - "codex cli", "codex-cli", "Codex", "openai" → "codex"
/// - "<agent_name>", "agent_name", unknown → falls back to "claude"
fn normalize_agent_name(name: &str) -> String {
    let lower = name.trim().to_lowercase();

    // Strip angle brackets (LLM placeholder artifacts like "<agent_name>")
    let cleaned = lower.trim_matches(|c| c == '<' || c == '>').trim().to_string();

    if cleaned == "claude" || cleaned == "claude code" || cleaned == "claude-code" || cleaned == "claude_code" {
        return "claude".to_string();
    }
    if cleaned == "gemini" || cleaned == "gemini cli" || cleaned == "gemini-cli" || cleaned == "gemini_cli" {
        return "gemini".to_string();
    }
    if cleaned == "codex" || cleaned == "codex cli" || cleaned == "codex-cli" || cleaned == "codex_cli" || cleaned == "openai" {
        return "codex".to_string();
    }

    // If it's a placeholder or unknown, default to claude
    log::warn!("[orchestrator] Unknown agent name '{}', defaulting to 'claude'", name);
    "claude".to_string()
}

/// Normalize all agent names in a DecompositionResult to valid tool names.
fn normalize_decomposition_agents(mut result: DecompositionResult) -> DecompositionResult {
    for task in &mut result.tasks {
        task.agent = normalize_agent_name(&task.agent);
    }
    result
}

/// Parse the master agent's decomposition JSON output.
/// Tries multiple strategies to extract a JSON object from the output,
/// handling markdown fences, natural language wrapping, and alternative key names.
///
/// Strategies (in order):
/// 1. Direct parse of the entire output
/// 2. Extract from markdown code fences (```json ... ```)
/// 3. Extract from first `{` to last `}`
/// 4. Scan for `"tasks"` key and extract the enclosing object
/// 5. Find any JSON array `[{...}]` and wrap as `{"tasks": [...]}`
///
/// Also handles alternative key names: `sub_tasks`, `subtasks` -> `tasks`.
fn parse_decomposition_json(output: &str) -> Option<DecompositionResult> {
    let trimmed = output.trim();

    // Strategy 1: Direct parse
    if let Some(result) = try_parse_decomposition(trimmed) {
        debug!("[orchestrator] parse_decomposition_json: Strategy 1 (direct) succeeded");
        return Some(result);
    }
    debug!("[orchestrator] parse_decomposition_json: Strategy 1 (direct) failed");

    // Strategy 2: Extract from markdown code fences
    if let Some(start) = output.find("```json") {
        let after_fence = &output[start + 7..];
        let json_str = if let Some(end) = after_fence.find("```") {
            &after_fence[..end]
        } else {
            after_fence
        };
        if let Some(result) = try_parse_decomposition(json_str.trim()) {
            debug!("[orchestrator] parse_decomposition_json: Strategy 2 (markdown fence) succeeded");
            return Some(result);
        }
        debug!("[orchestrator] parse_decomposition_json: Strategy 2 (markdown fence) failed");
    } else if let Some(start) = output.find("```") {
        // Try plain ``` fence (no json tag)
        let after_fence = &output[start + 3..];
        if let Some(end) = after_fence.find("```") {
            let json_str = &after_fence[..end];
            if let Some(result) = try_parse_decomposition(json_str.trim()) {
                debug!("[orchestrator] parse_decomposition_json: Strategy 2 (plain fence) succeeded");
                return Some(result);
            }
        }
        debug!("[orchestrator] parse_decomposition_json: Strategy 2 (plain fence) failed");
    }

    // Strategy 3: First `{` to last `}`
    if let (Some(start), Some(end)) = (output.find('{'), output.rfind('}')) {
        if start < end {
            let json_str = &output[start..=end];
            if let Some(result) = try_parse_decomposition(json_str.trim()) {
                debug!("[orchestrator] parse_decomposition_json: Strategy 3 (braces) succeeded");
                return Some(result);
            }
            debug!("[orchestrator] parse_decomposition_json: Strategy 3 (braces) failed");
        }
    }

    // Strategy 4: Scan for `"tasks"` key and extract the enclosing object
    // This handles cases where the JSON is deeply embedded in natural language
    if let Some(result) = extract_tasks_key_object(output) {
        debug!("[orchestrator] parse_decomposition_json: Strategy 4 (tasks key scan) succeeded");
        return Some(result);
    }
    debug!("[orchestrator] parse_decomposition_json: Strategy 4 (tasks key scan) failed");

    // Strategy 5: Find any JSON array `[{...}]` and wrap as `{"tasks": [...]}`
    if let Some(result) = extract_json_array_as_tasks(output) {
        debug!("[orchestrator] parse_decomposition_json: Strategy 5 (array wrap) succeeded");
        return Some(result);
    }
    debug!("[orchestrator] parse_decomposition_json: Strategy 5 (array wrap) failed — all strategies exhausted");

    None
}

/// Try to parse a JSON string as DecompositionResult, handling alternative key names.
/// Maps `sub_tasks` and `subtasks` to `tasks` before parsing.
fn try_parse_decomposition(json_str: &str) -> Option<DecompositionResult> {
    // Try direct parse first
    if let Ok(result) = serde_json::from_str::<DecompositionResult>(json_str) {
        if !result.tasks.is_empty() {
            return Some(result);
        }
    }

    // Try parsing as generic JSON and mapping alternative key names
    if let Ok(mut obj) = serde_json::from_str::<serde_json::Value>(json_str) {
        if let Some(map) = obj.as_object_mut() {
            // Map sub_tasks -> tasks
            if map.contains_key("sub_tasks") && !map.contains_key("tasks") {
                if let Some(val) = map.remove("sub_tasks") {
                    map.insert("tasks".to_string(), val);
                }
            }
            // Map subtasks -> tasks
            if map.contains_key("subtasks") && !map.contains_key("tasks") {
                if let Some(val) = map.remove("subtasks") {
                    map.insert("tasks".to_string(), val);
                }
            }

            if let Ok(result) = serde_json::from_value::<DecompositionResult>(obj) {
                if !result.tasks.is_empty() {
                    return Some(result);
                }
            }
        }
    }

    None
}

/// Strategy 4: Find `"tasks"` (or alternative keys) in the output and extract
/// the enclosing JSON object by bracket-matching from the preceding `{`.
fn extract_tasks_key_object(output: &str) -> Option<DecompositionResult> {
    for key in &["\"tasks\"", "\"sub_tasks\"", "\"subtasks\""] {
        if let Some(key_pos) = output.find(key) {
            // Walk backwards from the key to find the opening `{`
            let before = &output[..key_pos];
            if let Some(obj_start) = before.rfind('{') {
                // Walk forward from key to find the matching `}` using bracket counting
                let from_start = &output[obj_start..];
                if let Some(obj_end) = find_matching_brace(from_start) {
                    let json_str = &from_start[..=obj_end];
                    if let Some(result) = try_parse_decomposition(json_str.trim()) {
                        return Some(result);
                    }
                }
            }
        }
    }
    None
}

/// Strategy 5: Find a JSON array `[{...}]` in the output and wrap it as `{"tasks": [...]}`.
fn extract_json_array_as_tasks(output: &str) -> Option<DecompositionResult> {
    // Find the first `[{` pattern
    let arr_start = output.find("[{")?;
    let from_start = &output[arr_start..];

    // Find the matching `]` using bracket counting
    let arr_end = find_matching_bracket(from_start)?;
    let arr_str = &from_start[..=arr_end];

    // Verify it parses as a JSON array
    if let Ok(arr) = serde_json::from_str::<serde_json::Value>(arr_str) {
        if arr.is_array() {
